150	// without ever calling submit. On pass, honoured checks-bypass annotations are
151	// recorded as checks-bypass events and submit runs normally.
152	//
153	// submit is the project's land coordinator entry point (typically
154	// LocalLandCoordinator.Submit or the server-side coordinator submit).
155	//
156	// The implementation lives in checks_premerge.go alongside its supporting
157	// helpers (RunPreMergeChecks, AppendPreMergeChecksEvents,
158	// PreserveAfterPreMergeChecks); this thin wrapper exists so the execute-bead
159	// loop's land-back call site is one obvious helper rather than three nested
160	// ones, and so callers wiring the gate do not need to import the helper layer
161	// directly.
162	func SubmitWithPreMergeChecks(
163		ctx context.Context,
164		projectRoot string,
165		b *bead.Bead,
166		res *ExecuteBeadResult,
167		submit func(LandRequest) (*LandResult, error),
168		eventStore BeadEventAppender,
169		actor, source string,
170		now func() time.Time,
171	) (*LandResult, *PreMergeChecksOutcome, error) {
172		if now == nil {
173			now = time.Now
174		}
175		if submit == nil {
176			return nil, nil, fmt.Errorf("submit-with-pre-merge-checks: submit callback required")
177		}
178		evidenceDir := filepath.Join(projectRoot, res.ExecutionDir)
179		outcome, err := RunPreMergeChecks(ctx, projectRoot, b, res.BaseRev, res.ResultRev, evidenceDir)
180		if err != nil {
181			// Treat checks_bypass / loader errors as a hard preserve: the worker
182			// did its job; the operator misconfigured the gate. Better to park
183			// the result under an iteration ref than to silently land it.
184			ref := PreserveRef(res.BeadID, res.BaseRev)
185			if upErr := (&RealOrchestratorGitOps{}).UpdateRef(projectRoot, ref, res.ResultRev); upErr != nil {
186				return nil, nil, fmt.Errorf("preserving result after checks setup error: %w (original error: %v)", upErr, err)
187			}
188			return &LandResult{
189				Status:      "preserved",
190				PreserveRef: ref,
191				Reason:      "pre-merge checks setup error: " + err.Error(),
192			}, nil, nil
193		}
194		if outcome.Blocked {
195			land, perr := PreserveAfterPreMergeChecks(projectRoot, res, outcome, &RealOrchestratorGitOps{})
196			if perr != nil {
197				return nil, outcome, perr
198			}
199			if eventStore != nil {
200				_ = AppendPreMergeChecksEvents(eventStore, res.BeadID, outcome, actor, source, now().UTC())
201			}
202			return land, outcome, nil
203		}
204		if eventStore != nil && len(outcome.Bypassed) > 0 {
205			_ = AppendPreMergeChecksEvents(eventStore, res.BeadID, outcome, actor, source, now().UTC())
206		}
207		land, sErr := submit(BuildLandRequestFromResult(projectRoot, res))
208		return land, outcome, sErr
209	}
