211	// handlePostAttemptDecomposition runs the orchestrator-level splitter when a
212	// no_changes attempt signals orchestrator_action: decompose. It checks the
213	// queue-level max_decomposition_depth (not the implementation prompt cap),
214	// validates the AC map for completeness, and either creates children+deps or
215	// parks the parent for operator review if the split is lossy or depth-capped.
216	// The bead must already be unclaimed before this is called.
217	func (w *ExecuteBeadWorker) handlePostAttemptDecomposition(ctx context.Context, candidate *bead.Bead, runtime ExecuteBeadLoopRuntime, assignee string, rcfg config.ResolvedConfig, at time.Time) {
218		emit := func(kind string, body map[string]any) {
219			if runtime.EventSink == nil {
220				return
221			}
222			data, _ := json.Marshal(map[string]any{"event": kind, "payload": body})
223			_, _ = fmt.Fprintf(runtime.EventSink, "%s\n", data)
224		}
225		parkOperator := func(reason string) {
226			if runtime.Log != nil {
227				_, _ = fmt.Fprintf(runtime.Log, "post-attempt decomposition blocked: %s (%s)\n", reason, candidate.ID)
228			}
229			emit("post_attempt_decomposition.blocked", map[string]any{
230				"bead_id": candidate.ID,
231				"reason":  reason,
232			})
233			if berr := parkBeadPostIntakeRejection(w.Store, candidate.ID, assignee, PreClaimIntakeOperatorRequired, reason, at); berr != nil && runtime.Log != nil {
234				_, _ = fmt.Fprintf(runtime.Log, "post-attempt decomposition park error: %v\n", berr)
235			}
236		}
237	
238		// Queue-level depth check: orchestrator uses its own cap, not the
239		// implementation prompt's hardcoded depth-2 cap.
240		maxDepth := rcfg.MaxDecompositionDepth()
241		if maxDepth > 0 && storeBeadDepth(w.Store, candidate) >= maxDepth {
242			overflowBody, _ := json.Marshal(map[string]any{
243				"depth": storeBeadDepth(w.Store, candidate),
244				"max":   maxDepth,
245			})
246			_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
247				Kind:      "triage-overflow",
248				Summary:   "depth cap exceeded during post-attempt decomposition",
249				Body:      string(overflowBody),
250				Actor:     assignee,
251				Source:    "ddx agent execute-loop",
252				CreatedAt: at,
253			})
254			parkOperator("queue-level depth cap exceeded; operator must split")
255			return
256		}
257	
258		decomp, err := runtime.PostAttemptDecompositionHook(ctx, candidate.ID)
259		if err != nil {
260			parkOperator(fmt.Sprintf("decomposition hook error: %s", err.Error()))
261			return
262		}
263		if decomp == nil {
264			parkOperator("decomposition hook returned no split")
265			return
266		}
267		lossyOrEmpty := isDecompositionLossy(decomp.ACMap) || (len(decomp.ACMap) == 0 && strings.TrimSpace(candidate.Acceptance) != "")
268		if lossyOrEmpty {
269			parkOperator("decomposition AC map is incomplete; operator must produce a lossless split")
270			return
271		}
272	
273		childIDs, decompErr := applyPreClaimDecomposition(w.Store, candidate, decomp, assignee, at)
274		if decompErr != nil {
275			parkOperator(fmt.Sprintf("decomposition apply error: %s", decompErr.Error()))
276			return
277		}
278		if runtime.Log != nil {
279			_, _ = fmt.Fprintf(runtime.Log, "post-attempt decomposition: bead %s split into %s\n", candidate.ID, strings.Join(childIDs, ", "))
280		}
281		emit("post_attempt_decomposition.applied", map[string]any{
282			"bead_id":   candidate.ID,
283			"child_ids": childIDs,
284		})
285	}
