287	// runPostAttemptTriage invokes the optional post-attempt triage hook after
288	// the attempt outcome has been finalized but before any cooldown decision is
289	// applied. Hook failures are fail-open: the report is returned unchanged and
290	// legacy cooldown behavior remains in force.
291	func (w *ExecuteBeadWorker) runPostAttemptTriage(ctx context.Context, candidate bead.Bead, report ExecuteBeadReport, runtime ExecuteBeadLoopRuntime, assignee string, now func() time.Time) ExecuteBeadReport {
292		hook := runtime.PostAttemptTriageHook
293		if hook == nil {
294			return report
295		}
296		if isDeterministicSystemOutcomeReason(report.OutcomeReason) {
297			return report
298		}
299		triage, err := hook(ctx, candidate.ID, report)
300		if err != nil {
301			if runtime.Log != nil {
302				_, _ = fmt.Fprintf(runtime.Log, "post-attempt triage error (%s %s): %v (continuing)\n", candidate.ID, report.Status, err)
303			}
304			return report
305		}
306		triage = normalizeTriageResult(triage)
307		hasWarnings := len(triage.DecodeWarnings) > 0 || triage.Malformed
308		classificationRecognized := isRecognizedTriageClassification(triage.Classification)
309		if hasWarnings && runtime.Log != nil {
310			_, _ = fmt.Fprintf(runtime.Log, "post-attempt triage warning (%s %s): %s (continuing)\n", candidate.ID, report.Status, formatTriageWarnings(triage.DecodeWarnings))
311		}
312		if !classificationRecognized && !hasWarnings {
313			return report
314		}
315		if classificationRecognized {
316			report.OutcomeReason = triage.Classification
317		}
318		recordPostAttemptTriageEvent(w.Store, candidate.ID, report, triage, assignee, now().UTC())
319		return report
320	}
