9	// TestEscalatableStatusesMatchAgentVocab guards against drift between
10	// agent's ExecuteBeadStatus* constants and escalation.EscalatableStatuses.
11	// If you rename a status in execute_bead_status.go, update both places.
12	func TestEscalatableStatusesMatchAgentVocab(t *testing.T) {
13		expected := map[string]bool{
14			ExecuteBeadStatusExecutionFailed:    true,
15			ExecuteBeadStatusPostRunCheckFailed: true,
16			ExecuteBeadStatusLandConflict:       true,
17		}
18		for status := range expected {
19			if !escalation.EscalatableStatuses[status] {
20				t.Errorf("agent escalatable status %q is not in escalation.EscalatableStatuses", status)
21			}
22		}
23		for status := range escalation.EscalatableStatuses {
24			if !expected[status] {
25				t.Errorf("escalation.EscalatableStatuses has %q not in agent's expected set", status)
26			}
27		}
28		// SuccessStatus alignment
29		if escalation.SuccessStatus != ExecuteBeadStatusSuccess {
30			t.Errorf("escalation.SuccessStatus = %q, want %q (ExecuteBeadStatusSuccess)",
31				escalation.SuccessStatus, ExecuteBeadStatusSuccess)
32		}
