1751						if err := w.Store.SetExecutionCooldown(candidate.ID, retryAfter, report.Status, report.Detail, report.BaseRev); err != nil {
1752							_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
1753								return commitOutcomeError("SetExecutionCooldown", assignee, result, err)
1754							})
1755							if ctx.Err() != nil {
1756								return result, ctx.Err()
1757							}
1758							continue
1759						}
1760						report.RetryAfter = retryAfter.Format(time.RFC3339)
1761					}
1762					result.Failures++
1763					result.LastFailureStatus = report.Status
1764				default:
1765					report = w.runPostAttemptTriage(ctx, candidate, report, runtime, assignee, now)
1766					result.Failures++
1767					result.LastFailureStatus = report.Status
1768				}

1768				}
1769			} else {
1770				if attemptOut.Parking == nil && attemptOut.Disposition != agenttry.OutcomePark {
1771					if err := w.Store.Unclaim(candidate.ID); err != nil {
1772						_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
1773							return commitOutcomeError("Unclaim", assignee, result, err)
1774						})
1775						if ctx.Err() != nil {
1776							return result, ctx.Err()
1777						}
1778						continue
1779					}
1780				}
1781				if report.Status == ExecuteBeadStatusPreservedNeedsReview {
1782					if err := w.Store.AppendNotes(candidate.ID, preservedNeedsReviewNote(report)); err != nil {
1783						_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
1784							return commitOutcomeError("AppendNotes", assignee, result, err)
1785						})
1786						if ctx.Err() != nil {
1787							return result, ctx.Err()
1788						}
1789						continue
1790					}
1791					result.Failures++
1792					result.LastFailureStatus = report.Status
1793				} else {
1794					if isNoViableProviderReport(report) {
1795						report.OutcomeReason = FailureModeNoViableProvider
1796						retryAfter := now().UTC().Add(CapLoopCooldown(ProviderUnavailableCooldown))
1797						if err := w.Store.SetExecutionCooldown(candidate.ID, retryAfter, report.Status, report.Detail, report.BaseRev); err != nil {
1798							_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
1799								return commitOutcomeError("SetExecutionCooldown", assignee, result, err)
1800							})
1801							if ctx.Err() != nil {
1802								return result, ctx.Err()
1803							}
1804							continue
1805						}
1806						report.RetryAfter = retryAfter.Format(time.RFC3339)
1807					} else {
1808						report = w.runPostAttemptTriage(ctx, candidate, report, runtime, assignee, now)
1809						if shouldSuppressNoProgress(report) {
1810							retryAfter := now().UTC().Add(CapLoopCooldown(noProgressCooldown))
1811							if err := w.Store.SetExecutionCooldown(candidate.ID, retryAfter, report.Status, report.Detail, report.BaseRev); err != nil {
1812								_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
1813									return commitOutcomeError("SetExecutionCooldown", assignee, result, err)
1814								})
1815								if ctx.Err() != nil {
1816									return result, ctx.Err()
1817								}
1818								continue
1819							}
1820							report.RetryAfter = retryAfter.Format(time.RFC3339)
1821						}
1822					}
1823					result.Failures++
1824					result.LastFailureStatus = report.Status
1825				}
1826			}
1827	
1828			result.Results = append(result.Results, report)
1829	
1830			// Skip the late execute-bead append for already-satisfied beads —
1831			// the satisfied path appends its own terminal event before
1832			// CloseWithEvidence so the closure gate sees execution evidence.
1833			// Duplicating it here would yield two identical events.
1834			if report.Status != ExecuteBeadStatusAlreadySatisfied {
1835				if err := w.Store.AppendEvent(candidate.ID, executeBeadLoopEvent(report, assignee, now().UTC())); err != nil {
1836					_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
1837						return commitOutcomeError("AppendEvent", assignee, result, err)
1838					})
1839					// Event recording failure is non-terminal: log it and continue.
1840					// result counters were already updated by the outcome block above;
1841					// do not double-count by re-running the outcome handler.
1842					if runtime.Log != nil {
1843						_, _ = fmt.Fprintf(runtime.Log, "outcome store error (AppendEvent %s): %v (continuing)\n", candidate.ID, err)
1844					}
1845					if ctx.Err() == nil {
1846						_ = w.Store.SetExecutionCooldown(candidate.ID, now().UTC().Add(StoreErrorCooldown), "loop-error", "AppendEvent: "+err.Error(), "")
1847					}
1848					if ctx.Err() != nil {
1849						return result, ctx.Err()
1850					}
1851					continue
1852				}
1853			}
1854	
1855			// Emit terminal progress phase event.
1856			terminalPhase := "failed"
1857			if report.Status == ExecuteBeadStatusSuccess || report.Status == ExecuteBeadStatusAlreadySatisfied {
1858				terminalPhase = "done"
1859			} else if report.PreserveRef != "" {
1860				terminalPhase = "preserved"
1861			}
1862			// Use the real attempt_id from the report if available.
1863			finalAttemptID := report.AttemptID
1864			if finalAttemptID == "" {
1865				finalAttemptID = provAttemptID
1866			}
1867			phaseSeq++
1868			emitProgress(runtime.ProgressCh, ProgressEvent{
1869				EventID:   "evt-" + randomProgressID(),
1870				AttemptID: finalAttemptID,
1871				WorkerID:  runtime.WorkerID,
1872				ProjectID: runtime.ProjectRoot,
1873				BeadID:    candidate.ID,
1874				Harness:   harness,
1875				Model:     model,
1876				Profile:   profile,
1877				Phase:     terminalPhase,
1878				PhaseSeq:  phaseSeq,
1879				Heartbeat: false,
1880				TS:        now().UTC(),
1881				ElapsedMS: now().Sub(runStart).Milliseconds(),
1882				Message:   report.Detail,
1883			})
1884	
1885			emit("bead.result", map[string]any{
1886				"bead_id":              candidate.ID,
1887				"status":               report.Status,
1888				"detail":               report.Detail,
1889				"session_id":           report.SessionID,
1890				"result_rev":           report.ResultRev,
1891				"base_rev":             report.BaseRev,
1892				"preserve_ref":         report.PreserveRef,
1893				"no_changes_rationale": report.NoChangesRationale,
1894				"duration_ms":          now().Sub(runStart).Milliseconds(),
1895			})
1896	
1897			if runtime.Log != nil {
1898				_, _ = fmt.Fprintln(runtime.Log, formatLoopResultLine(candidate.ID, report))
1899			}
1900	
1901			if loopMode == executeloop.ModeOnce {
1902				applyStop(work.StopInput{Once: true})
1903				return result, nil
1904			}
1905		}
1906	}
