1951	// emitPickerPrioritySkips fires a picker.priority_skip event when the picker
1952	// chose `chosen` while at least one strictly higher-priority bead was passed
1953	// over (ddx-9d55601f AC #4). Skips at the same priority as `chosen` are NOT
1954	// reported — those are FIFO order or label-filter siblings, not starvation.
1955	//
1956	// The emit is guarded so it costs nothing when the chosen bead is the highest-
1957	// priority bead the picker saw (the common case).
1958	func emitPickerPrioritySkips(emit func(string, map[string]any), chosen bead.Bead, skips []pickerSkip) {
1959		if len(skips) == 0 {
1960			return
1961		}
1962		var higher []map[string]any
1963		for _, s := range skips {
1964			if s.Priority < chosen.Priority {
1965				higher = append(higher, map[string]any{
1966					"bead_id":    s.BeadID,
1967					"priority":   s.Priority,
1968					"queue_rank": queueRankValue(s.BeadRank),
1969					"reason":     s.Reason,
1970				})
1971			}
1972		}
1973		if len(higher) == 0 {
1974			return
1975		}
1976		emit("picker.priority_skip", map[string]any{
1977			"chosen_bead_id":  chosen.ID,
1978			"chosen_priority": chosen.Priority,
1979			"skipped":         higher,
1980		})
1981	}
1982	
1983	// pickerSkip records a single bead that the picker passed over while looking
1984	// for the next candidate. It is used to emit a structured picker.priority_skip
1985	// event when a worker claims a lower-priority bead while a higher-priority
1986	// bead was skipped, so future starvation regressions are observable.
1987	//
1988	// Reason values are bounded to the set named in ddx-9d55601f AC #4:
1989	//
1990	//	label_filter, in_attempted, claim_race, eligibility_filter, retry_cooldown
1991	//
1992	// Note: eligibility_filter and retry_cooldown are applied upstream in
1993	// Store.ReadyExecution (so beads filtered for those reasons never reach
1994	// nextCandidate at all). They are part of the reason vocabulary so future
1995	// picker rearrangements can re-emit them without changing the schema.
1996	type pickerSkip struct {
1997		BeadID   string
1998		Priority int
1999		BeadRank *int
2000		Reason   string
2001	}
2002	
2003	func hasGuardSkips(skips []pickerSkip) bool {
2004		for _, skip := range skips {
2005			switch skip.Reason {
2006			case "label_filter", "in_attempted", "claim_race", "eligibility_filter", "retry_cooldown", "target_bead":
2007				continue
2008			default:
2009				return true
2010			}
2011		}
2012		return false
2013	}
2014	
2015	func queueRankValue(raw any) any {
2016		rank, ok := parseQueueRank(raw)
2017		if !ok {
2018			return nil
2019		}
2020		return rank
2021	}
