426	func ctxSleep(ctx context.Context, d time.Duration) error {
427		if d <= 0 {
428			return nil
429		}
430		t := time.NewTimer(d)
431		defer t.Stop()
432		select {
433		case <-ctx.Done():
434			return ctx.Err()
435		case <-t.C:
436			return nil
437		}
438	}
